 1→import { defineConfig } from 'vitest/config'
 2→import react from '@vitejs/plugin-react'
 3→import { fileURLToPath, URL } from 'node:url'
 4→
 5→async function loadTddGuardReporter() {
 6→  const projectRoot = process.env.TDD_GUARD_PROJECT_ROOT
 7→  if (!projectRoot) {
 8→    return null
 9→  }
10→
11→  try {
12→    const dynamicImport = new Function('specifier', 'return import(specifier)') as (
13→      specifier: string,
14→    ) => Promise<{ VitestReporter?: new (root: string) => unknown }>
15→    const mod = await dynamicImport('tdd-guard-vitest')
16→    if (!mod.VitestReporter) {
17→      throw new Error('tdd-guard-vitest did not export VitestReporter')
18→    }
19→    return new mod.VitestReporter(projectRoot)
20→  } catch (error) {
21→    if (process.env.TDD_GUARD_REQUIRED === '1') {
22→      throw error
23→    }
24→    console.warn('vitest: tdd-guard-vitest not installed; continuing without TDD Guard reporter')
25→    return null
26→  }
27→}
28→
29→export default defineConfig(async () => {
30→  const tddGuardReporter = await loadTddGuardReporter()
31→
32→  return {
33→    plugins: [react()],
34→    resolve: {
35→      alias: {
36→        '@': fileURLToPath(new URL('./src', import.meta.url)),
37→      },
38→    },
39→    test: {
40→      environment: 'happy-dom',
41→      setupFiles: ['./src/test/setup.ts'],
42→      exclude: ['e2e/**', 'node_modules/**'],
43→      reporters: tddGuardReporter ? ['default', tddGuardReporter] : ['default'],
44→      coverage: {
45→        provider: 'v8',
46→        reporter: ['text', 'lcov'],
47→        include: ['src/**/*.{ts,tsx}'],
48→        exclude: ['src/test/**', 'src/**/*.test.{ts,tsx}', 'src/main.tsx', 'src/vite-env.d.ts'],
49→        thresholds: {
50→          lines: 80,
51→          functions: 80,
52→          branches: 80,
53→          statements: 80,
54→        },
55→      },
56→    },
57→  }
58→})
59→

